import{_ as s,o as p,c as i,a2 as e}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"2.1 副本","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 副本根据性质可以分为以下五种： ①普通副本 ②英雄副本 ③跨服副本 ④团队副本 ⑤单人副本 其中可以单刷获得最大收益的有： ①（不推荐） ②⑤ 随着角色等级逐渐解锁的副本， 分别为： 王宫","frontmatter":{"title":"2.1 副本","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 副本根据性质可以分为以下五种： ①普通副本 ②英雄副本 ③跨服副本 ④团队副本 ⑤单人副本 其中可以单刷获得最大收益的有： ①（不推荐） ②⑤ 随着角色等级逐渐解锁的副本， 分别为： 王宫","outline":"deep"},"headers":[],"relativePath":"pve/2-1.md","filePath":"pve/2-1.md","lastUpdated":1782387794000}'),t={name:"pve/2-1.md"};function u(g,a,l,r,o,f){return p(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="_2-1-副本" tabindex="-1">2.1 副本 <a id="s130-b56235c4"></a> <a class="header-anchor" href="#_2-1-副本" aria-label="Permalink to &quot;2.1 副本 &lt;a id=&quot;s130-b56235c4&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_2-1-1-副本的种类" tabindex="-1">2.1.1 副本的种类 <a id="s131-2f2aecd1"></a> <a class="header-anchor" href="#_2-1-1-副本的种类" aria-label="Permalink to &quot;2.1.1 副本的种类 &lt;a id=&quot;s131-2f2aecd1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>副本根据性质可以分为以下五种：</p><p>①普通副本</p><p>②英雄副本</p><p>③跨服副本</p><p>④团队副本</p><p>⑤单人副本</p><p>其中可以单刷获得最大收益的有：</p><p>①（不推荐）</p><p>②⑤</p><h2 id="_2-1-2-普通副本" tabindex="-1">2.1.2 普通副本 <a id="s132-d88d96bb"></a> <a class="header-anchor" href="#_2-1-2-普通副本" aria-label="Permalink to &quot;2.1.2 普通副本 &lt;a id=&quot;s132-d88d96bb&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>随着角色等级逐渐解锁的副本，</p><p>分别为：</p><p>王宫下水道、风刃废矿、燃烧之城武器库、哈迪尔农场、呼啸深渊、毁灭之源。</p><p>但是游戏内说这些名字一般指代他们的英雄级副本，即所谓的H 本。</p><p>8.5 更新后娜刹什也拥有了普通副本和英雄副本的区别，娜刹什伽尔是推荐击杀普通副本的，因为英雄副本单刷难度过大。</p><h2 id="_2-1-3-英雄副本" tabindex="-1">2.1.3 英雄副本 <a id="s133-f98f4b39"></a> <a class="header-anchor" href="#_2-1-3-英雄副本" aria-label="Permalink to &quot;2.1.3 英雄副本 &lt;a id=&quot;s133-f98f4b39&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>角色到达55 级后解锁的副本。游戏内会加【英雄副本】的前缀。</p><p>一共有7 个，分别为</p><p>王宫下水道、</p><p>风刃废矿（18H）、</p><p>燃烧之城武器库(30H)、</p><p>哈迪尔农场、</p><p>呼啸深渊(40H)、</p><p>毁灭之源、</p><p>娜刹什伽尔（俗称的陆地十人本，单刷英雄难度较大）。</p><p>进入与离开这些副本单刷流程如下图所示：</p><p>然后就会进入等待时间（第一把可能久一点，一般就几秒钟）</p><p>离开副本操作如下：</p><p>走近红框的绿圈圈处会出现交互键，点击交互键即可离开。</p><p>或者你可以点击右上角的快速离开键来离开。</p><p>游戏级副本掉落物有：</p><p>1）武器、防具、未鉴定的饰品</p><p>2）深渊碎片、深渊结晶</p><p>3）时装经验石头碎片</p><p>4）沉甸甸的袋子</p><p>5）坐骑和战宠装备</p><p>6）新月血石</p><p>7）经验成长石</p><p>8）蕴含灵魂的祝福石</p><p>9）永恒的夏日之息、永恒的冬日之寒</p><p>呼啸深渊关底BOSS 会额外掉落古神教的宝箱和一个战宠，如图所示：</p><p>副本每日击杀关底BOSS 任务如下图：</p><p>单刷英雄副本流程可以参考笔者B 站视频：</p><p>王宫下水道：待更新</p><p>风刃废矿：BV1PPhkeFEG8</p><p>燃烧之城武器库：BV1cy8Re4EqL</p><p>哈迪尔农场：BV1fGhkeXEL7</p><p>呼啸深渊：BV1ZohkeXEMw</p><p>娜刹什伽尔F：BV1Abhpe3EmV</p><p>娜刹什伽尔掉落：</p><p>武器（分解出精华）、防具（分解出晶片）、饰品（分解出晶片）、BUFF 药、强化菱石、新月血石。</p><p>单刷娜刹什伽尔注意事项：</p><p>老三血色微笑有扣血机制可以避免，无敌或者流星火雨都可以，推荐法师憎恨一套连后直接流星火雨可以节约血药。</p><p>老四巴尔基依旧有无法解除末日劫火的BUG（BOSS 掉血过快），担心的话可以带铁壁的无敌来防止。被末日劫火击中后需要尽快前往发光的石板，没有发光就等到石板发光，大概1S 内会弹DEBUFF 解除，这样子就需要离开石板，不然石板爆炸伤害还是很高的。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1680.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1687.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1688.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1693.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1694.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1699.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1700.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1705.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1706.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1711.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1712.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1717.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1718.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1724.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1725.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1726.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1727.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1728.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1729.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1730.jpeg" alt="图示：2.1.3 英雄副本" loading="lazy"></figure><ul><li>另有 5 张图像，详见 <code>image_manifest.csv</code>。</li></ul><h2 id="_2-1-4-英雄副本的收益分析" tabindex="-1">2.1.4 英雄副本的收益分析 <a id="s134-3f4487a5"></a> <a class="header-anchor" href="#_2-1-4-英雄副本的收益分析" aria-label="Permalink to &quot;2.1.4 英雄副本的收益分析 &lt;a id=&quot;s134-3f4487a5&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>单刷副本毕业参考时间（以法师为例，从过图结束开始计时）如下：</p><p>武器库100s</p><p>农场185s</p><p>废矿150s</p><p>下水道190s （能跳过所有屏障）</p><p>下水道280s（不能跳过所有屏障）</p><p>呼啸470s</p><p>呼啸只刷第一个BOSS 蛇需要100s</p><p>娜刹什伽尔F 130S</p><p>英雄副本每天可以免费进入3 次，之后需要用副本刷新券才能再次进入，进入次数越多，所需要的券就越多。除了武器库，其他英雄副本第四次刷取都为1 张刷新券，</p><p>武器库为3 张。</p><p>掉落分析如下：</p><p>副本路上小BOSS 必掉冬日或者夏日其中一个</p><p>路上小BOSS 必掉一个防具（武器库和农场为武器）</p><p>必掉沉甸甸的袋子</p><p>必掉碎片和时装碎石</p><p>概率掉未鉴定的饰品</p><p>鉴定后分解给饰品源晶碎片</p><p>副本关底BOSS 必掉一个武器和一个防具（武器库和农场除外）、必掉蕴含灵魂的祝福石、概率掉血石（享受掉落BUFF）、必掉冬日或者夏日其中一个。</p><p>40H 小怪中概率掉防具</p><p>40H 第一个BOSS 蛇概率掉落一件防具，箱子必定掉落一件防具。</p><p>第二个BOSS 概率掉落3 个防具（一般掉落2 个）</p><p>第三个BOSS 必定掉落一把武器并概率掉一个防具</p><p>第四个概率掉两件防具</p><p>关底BOSS 必定掉落一把武器、一件防具、古神教宝箱、战宠、概率掉落血石娜刹什伽尔的英雄本BOSS 不掉落时装经验石头碎片，其余奖励和F 本一样。</p><p>娜刹什伽尔除了关底BOSS 直接掉落装备和血石，其他BOSS 只有时装经验石头，</p><p>装备在打完BOSS 后出的箱子里。</p><p>守门老一的箱子出坐骑装备，可以搞个坐骑蹄子用用，其他的无用。</p><p>老二箱子出墟境迷宫的珍贵保管箱，并概率出卡尔米拉的回忆（耳环）。</p><p>老三箱子出一把武器和四件防具和1-2 个（武器/防具）强化菱石，概率掉落一个防具箱子（至少出一件防具）或者一个武器箱子（至少出一把武器）或者一个墟境迷宫补给箱。</p><p>关底巴尔基必定掉落一把武器和一个血石、概率额外掉落第二把武器。</p><p>娜刹什伽尔副本掉落的武器分解了直接给武器源晶精华，防具分解给防具源晶晶片，饰品分解给饰品源晶晶片。</p><p>分解石头如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1753.jpeg" alt="图示：2.1.4 英雄副本的收益分析" loading="lazy"></figure><h2 id="_2-1-5-跨服副本" tabindex="-1">2.1.5 跨服副本 <a id="s135-7ea91b9a"></a> <a class="header-anchor" href="#_2-1-5-跨服副本" aria-label="Permalink to &quot;2.1.5 跨服副本 &lt;a id=&quot;s135-7ea91b9a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>跨服副本包括以下：</p><p>伊弗尼尔的黄金圣所、诺尔耶无限大战、沉入深渊的埃尔纳图书馆、永恒之岛、</p><p>烟飨之庭。</p><h3 id="伊弗尼尔的黄金圣所" tabindex="-1">伊弗尼尔的黄金圣所 <a id="s136-2b6849a9"></a> <a class="header-anchor" href="#伊弗尼尔的黄金圣所" aria-label="Permalink to &quot;伊弗尼尔的黄金圣所 &lt;a id=&quot;s136-2b6849a9&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>正常刷本流程参考贴吧君思文大佬攻略：</p><p><a href="https://tieba.baidu.com/p/7313567668?see_lz=1%E5%9C%A3%E6%89%80%E5%8D%A1BUG" target="_blank" rel="noreferrer">https://tieba.baidu.com/p/7313567668?see_lz=1圣所卡BUG</a> 流程可以参考视频：待更新伊弗尼尔的黄金圣所卡BUG 流程仅打老二和老四。</p><p>卡BUG 前你需要准备一个额外的天赋页和足球鞋。</p><p>足球鞋可以在监狱拿到，或者直接拍卖行也可以。</p><p>足球鞋如下：</p><p>圣所天赋页如下：</p><p>刷圣所的主要收益为：圣所瓶子、觉醒材料、圣所装备</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1758.jpeg" alt="图示：伊弗尼尔的黄金圣所" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1767.jpeg" alt="图示：伊弗尼尔的黄金圣所" loading="lazy"></figure><h3 id="诺尔耶无限大战" tabindex="-1">诺尔耶无限大战 <a id="s137-a6269748"></a> <a class="header-anchor" href="#诺尔耶无限大战" aria-label="Permalink to &quot;诺尔耶无限大战 &lt;a id=&quot;s137-a6269748&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>攻略流程可以参考笔者B 站视频：</p><p>30 和50 收益分别为：</p><p>打50 层主要是为了深渊碎片，5 个可以合成一个随机的圣所石头，不是自己想要的可以分解成碎片。</p><p>可以通过以下流程查看圣所石头属性：</p><p>诺尔耶只要输出足够，参与人员知晓机制并且没有死亡，就会5 层5 层跳关，不需要一层层的打。队伍配置高、配合好、会打10 分钟就能打完，不懂机制+伤害不够</p><p>1 小时也拿不下来。</p><p>前面关卡输出够+扒皮就可以不用管BOSS 机制（滑稽）</p><p>不管是哪层诺尔耶都需要优先清掉BOSS。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1768.jpeg" alt="图示：诺尔耶无限大战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1769.jpeg" alt="图示：诺尔耶无限大战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1775.jpeg" alt="图示：诺尔耶无限大战" loading="lazy"></figure><h3 id="沉入深渊的埃尔纳图书馆" tabindex="-1">沉入深渊的埃尔纳图书馆 <a id="s138-4386085e"></a> <a class="header-anchor" href="#沉入深渊的埃尔纳图书馆" aria-label="Permalink to &quot;沉入深渊的埃尔纳图书馆 &lt;a id=&quot;s138-4386085e&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>老一老二老三如果队伍输出足够就不用担心机制。</p><p>老一的机制是BOSS 身上会出现有颜色的光球，你需要去触碰同颜色的光球来避免BOSS 的高额伤害。</p><p>老二是会出线状闪电，延迟伤害，奶妈可以提前缓回，或者走位避开也行。</p><p>老三是会出一个大书怪</p><p>老四是最容易翻车的BOSS，老四，需要一个人拿休息室NPC 旁边的杖，用来堵上BOSS 房间出现的裂缝，裂缝会越来越大，召唤出来的小怪也会越来越多。</p><p>老四最重要的机制就是旋转大炮，BOSS 会先变成球形回到地图中心，然后向仇恨最高的人方向开始开炮，每炮伤害倍增，够肉可以逆旋转方向硬吃2 炮，或者吟游加速跑过去，你要是实在搞不明白或者操作不过来，就在老四房间切成带铁壁的天赋，</p><p>看到大炮就直接开无敌。</p><h3 id="永恒之岛" tabindex="-1">永恒之岛 <a id="s139-379bee6b"></a> <a class="header-anchor" href="#永恒之岛" aria-label="Permalink to &quot;永恒之岛 &lt;a id=&quot;s139-379bee6b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>输出足够爆炸的话，有没有戒指都没影响。不是毕业装备队伍最好还是带上戒指（伊尼斯、公主梦、大象戒指其中一个）。出小怪清小怪即可。</p><h3 id="烟飨之庭" tabindex="-1">烟飨之庭 <a id="s140-7a2e9522"></a> <a class="header-anchor" href="#烟飨之庭" aria-label="Permalink to &quot;烟飨之庭 &lt;a id=&quot;s140-7a2e9522&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>（新版本烟飨可以直接快速进入）</p><p>输出够走中间大路，不够走旁边机制小路。不管走那边都要记得打完怪后拿箱子里的钥匙开门。</p><p>想打伊修达尔的话，需要饕餮、阿莉亚、白娘子都要打过高级获得BUFF 才能开门。</p><p>饕餮、阿莉亚、白娘子不管什么难度机制其实都是一样的，不过高级机制给你的容错范围更少，伤害更高。</p><p>饕餮需要站在没有尖刺石板的地面上，BOSS 掉一定血后会把所有人弹开并减速，</p><p>需要快速离开地图边缘，不然会死。</p><p>阿莉亚在唱歌时，地面上会出现颜色方块，出现红色和绿色方块后，需要站到绿色方块上。</p><p>白娘子会喷蛇毒，不一直站在蛇毒上就不会石化。白娘子还有一个机制是出高额减伤然后出灯笼怪，需要站在灯笼怪的篮圈里面打死灯笼怪，然后走到后面的楼梯爬上去按F 交互解除一个减伤符咒，重复至清除全部符咒即可。</p><p>打伊修达尔注意不要掉下平台就好。</p><h2 id="_2-1-6-团队副本" tabindex="-1">2.1.6 团队副本 <a id="s141-24f7eef8"></a> <a class="header-anchor" href="#_2-1-6-团队副本" aria-label="Permalink to &quot;2.1.6 团队副本 &lt;a id=&quot;s141-24f7eef8&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>团队副本有以下3 种：</p><p>①红龙巢穴②血之使者卡杜姆③悉拉玛卡的末日</p><p>收益最高的是①，②偶尔也有人打但是不多，③则是完全没人打，所以本篇攻略不做展开。</p><p>1 ②③的装备评分要求分别为：5000、8000、4000</p><h3 id="_1红龙-rd" tabindex="-1">①红龙（RD） <a id="s142-6f981738"></a> <a class="header-anchor" href="#_1红龙-rd" aria-label="Permalink to &quot;①红龙（RD） &lt;a id=&quot;s142-6f981738&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>1 红龙（RD）</p><p>红龙属于人多比较好打的BOSS，只要准点去排就好。可以进入时间为：</p><p>中国时间一三五七晚上7：30 和11：00；一二四六早上8：00。</p><p>萌新进去后避免站在人堆被BOSS 技能砸死就好，或者可以带一个意志，点上反伤，帮助团队更快击落红龙。红龙死亡时人在150M 内即可复活舔尸。</p><p>如果你想加快红龙下来的速度，那么你还可以准备一个乌龟（需在成团前召唤），</p><p>因为乌龟反伤很高（天赋技能都是先减伤再反伤，伤害较少）。乌龟如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1791.jpeg" alt="图示：①红龙（RD）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1792.jpeg" alt="图示：①红龙（RD）" loading="lazy"></figure><h3 id="_2卡杜姆-kadum" tabindex="-1">②卡杜姆（kadum） <a id="s143-f818bd86"></a> <a class="header-anchor" href="#_2卡杜姆-kadum" aria-label="Permalink to &quot;②卡杜姆（kadum） &lt;a id=&quot;s143-f818bd86&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>2 卡杜姆（kadum）</p><p>这个BOSS 难度较高，如果你们团里人都不都你机制导致人死完了，那么可能到黄金你们都打不死这个BOSS，但是知道机制后这个BOSS 难度其实也就一般。（尤其是现在版本装备好很多，难度其实以及大大下降，30 人都能很快打死）</p><p>卡杜姆的进入时间和红龙刚刚好岔开，如下：</p><p>中国时间二四六七晚上7：30 和11：00；一三五七早上8：00。</p><p>卡杜姆技能和机制如下：</p><p>卡杜姆右手强击之后藤蔓范围大概在75 米，用无敌技能或者无敌翅膀或者提前往外飞都可以避免被束缚，奶妈可以直接用光与暗自救或者救别人（本质是束缚DEBUFF，能解束缚就没事），时间不是很紧张，不是太脆不用怕。</p><p>藤蔓技能之后会出现水泡，boss 后会有树枝升起、地上会出现蓝色圈圈，蓝色圈圈就是水泡落下的位置，落下之后会形成水泡陷阱，这个水泡陷阱几乎必死，因为在水泡里面至少会掉80%的血（可用霸气解除）。</p><p>boss30%的血之后boss 会关闭祭坛，此时祭坛上的人无法下来切会有2-3 波的无右手强击的预警的藤蔓。</p><p>需要注意的是别掉进祭坛下的水里，死亡后在祭坛复活点另一端召唤坐骑下去，</p><p>滑翔翼会因为死喘无法使用。</p><p>BOSS 击飞太高可使用滑翔翼或者前跳后跳来避免掉落伤害。</p><p>BOSS 奖励如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1804.jpeg" alt="图示：②卡杜姆（kadum）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1805.jpeg" alt="图示：②卡杜姆（kadum）" loading="lazy"></figure><h2 id="_2-1-7-单人副本-冥界之夜" tabindex="-1">2.1.7 单人副本（冥界之夜） <a id="s144-11c2a8b6"></a> <a class="header-anchor" href="#_2-1-7-单人副本-冥界之夜" aria-label="Permalink to &quot;2.1.7 单人副本（冥界之夜） &lt;a id=&quot;s144-11c2a8b6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>刷本流程参考B 站视频：BV1h44y1c7RV</p><p>NPC 任务参考苏夭夭大佬攻略：<a href="https://tieba.baidu.com/p/6747068489?see_lz=0" target="_blank" rel="noreferrer">https://tieba.baidu.com/p/6747068489?see_lz=0</a></p><h2 id="_2-1-8-势力对决-黄金" tabindex="-1">2.1.8 势力对决（黄金） <a id="s145-376c2fd1"></a> <a class="header-anchor" href="#_2-1-8-势力对决-黄金" aria-label="Permalink to &quot;2.1.8 势力对决（黄金） &lt;a id=&quot;s145-376c2fd1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>俗称的黄金，指的是势力对决里的势力荣誉战场，不是战场里的黄金平原大乱斗。</p><p>进入黄金流程如图：</p><p>这些图标在游戏画面右下角。</p><p>点击红框位置。</p><p>在可以进入黄金的时候，红框处会亮起，点击即可排队进入黄金。</p><p>注意：进入黄金以后不可以挂机出现暂离，暂离会有惩罚：无法进入战场的DEBUFF，挂了这个DEBUFF 之后就没法进黄金红龙副本这些了，而且该DEBUFF仅计算在线时间，暂离时间越久，DEBUFF 时间也越久（比例很恐怖的），而且黄金结束时如果是暂离，那将无法获得奖励（收不到邮件）。</p><p>进入黄金后想要获得奖励，则必须要有击杀/死亡/助攻，最简单的方法就是去对面送一个头。</p><p>黄金每个角色每天只能参加3 次，装备评分要求为:8000 以上。黄金的奖励会根据所在势力的排名不同而有所变化。第一名为4000 荣誉，如下图：</p><p>第二名为3000 荣誉，如下图：</p><p>黄金还有一个每日任务，可以在各个地图的战场募兵官处接取任务，如下：</p><p>基里奥斯的箱子（9.0 开始变为绿色品质的箱子）随机给60-100 个战场币。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1705.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1810.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1817.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1822.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1823.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1828.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1829.jpeg" alt="图示：2.1.8 势力对决（黄金）" loading="lazy"></figure><h2 id="_2-1-9-工会副本" tabindex="-1">2.1.9 工会副本 <a id="s146-46cc3273"></a> <a class="header-anchor" href="#_2-1-9-工会副本" aria-label="Permalink to &quot;2.1.9 工会副本 &lt;a id=&quot;s146-46cc3273&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>待更新</p><h2 id="_2-1-10-战场副本-跑海必看" tabindex="-1">2.1.10 战场副本（跑海必看） <a id="s147-950c90ce"></a> <a class="header-anchor" href="#_2-1-10-战场副本-跑海必看" aria-label="Permalink to &quot;2.1.10 战场副本（跑海必看） &lt;a id=&quot;s147-950c90ce&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>战场副本指的是在副本界面里战场一栏的所有项目，包括海战、角斗场、烟飨等。</p><p>攻略里将主要介绍海战副本，内容包括如何刷海战币和如何使用海战币兑换道具</p><h3 id="海战" tabindex="-1">海战 <a id="s148-43154fe7"></a> <a class="header-anchor" href="#海战" aria-label="Permalink to &quot;海战 &lt;a id=&quot;s148-43154fe7&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>进入海战的方式如下：</p><p>点开后选择队伍加入，然后准备即可。</p><p>注意！！！你可以在势力和跨服说嗨战，但是请不要把队伍链接发送出去。</p><p>在进海战前，记得先在任意一个地图的拍卖师那接任务（就是进幻想岛门旁边的那个鲁鲁），其中有一个任务是要连续赢3 把，先输的队伍在第四把开始前要重新接取连续赢3 把的任务。</p><p>要求连续赢3 把的任务如下图：</p><p>按照惯例，第一把进去船皮肤是蓝色的队伍先输3 把。</p><p>然后在打完5 把后，第六把开始前，游戏会问你是否重置，如果你第一把是蓝队，也就是第四把才开始做连续赢3 把的任务。这时候你需要一个道具，如下图：</p><p>重置一轮需要3 个这种币，打征兆给。</p><p>进入海战之后，找船上去驾驶，不管输还是赢都不要在家里待着。赢的队伍驾驶船之后去找海面上的剑，用船碰剑获取输出技能，输的队伍跟着队友上去送就行。</p><p>注意！！打完一把结束时，如果死了，等复活再点结束出去，不然出去后还是死的。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1839.jpeg" alt="图示：海战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1846.jpeg" alt="图示：海战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1852.jpeg" alt="图示：海战" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1853.jpeg" alt="图示：海战" loading="lazy"></figure><h3 id="兑换海战币道具" tabindex="-1">兑换海战币道具 <a id="s149-fe15d65f"></a> <a class="header-anchor" href="#兑换海战币道具" aria-label="Permalink to &quot;兑换海战币道具 &lt;a id=&quot;s149-fe15d65f&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>海战币的兑换地点有2 个，自由岛和光芒势力主城，其中海盗只能去自由岛兑换。</p><p>兑换台子如下红框：</p><p>自由岛的兑换台子和上面的外形一样。</p><p>主要兑换道具为以下两个：</p><p>第一个为海战船头，要330 个币，不能和箱子的亡灵收集器一起使用，而且加速幅度也不如箱子的，但是是范围BUFF，还加开炮速度，适合打海战。</p><p>第二个是隐身灯，要280 个币，对比手工灯优点在于：①轻，不会因为额外增重太多而减速②隐身结束可以立马续上，不需要像手工灯一样准备2 个应对空白期。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1858.jpeg" alt="图示：兑换海战币道具" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1864.jpeg" alt="图示：兑换海战币道具" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1865.jpeg" alt="图示：兑换海战币道具" loading="lazy"></figure>',240)])])}const h=s(t,[["render",u]]);export{c as __pageData,h as default};
